const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

export function quote(customer: Customer, items: Item[]): number {
  const counts: Record<string, number> = {};
  let policyBase = 0;

  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      counts[item.type] = (counts[item.type] ?? 0) + 1;
    } else {
      policyBase += BASE_PREMIUMS[item.type];
    }
  }

  for (const type of Object.keys(counts)) {
    const count = counts[type];
    const blocks = Math.floor(count / 3);
    const remainder = count % 3;
    policyBase += blocks * 60 + remainder * BASE_PREMIUMS[type];
  }

  return Math.ceil((policyBase * 11) / 10) + PROCESSING_FEE;
}
